import React from "react";
import { useNavigate } from "react-router-dom";

function ProjectCard({ project, onDelete, showDelete = false }) {
  const navigate = useNavigate();

  return (
    <div className="project-card">
      <div className="badge">Student Project</div>

      <h3>{project.title}</h3>

      <p>{project.description}</p>

      <p>
        <strong>Tech Stack:</strong> {project.techStack}
      </p>

      <div className="card-links">
        {project.githubLink && (
          <a href={project.githubLink} target="_blank" rel="noreferrer" className="card-link">
            GitHub Link
          </a>
        )}

        {project.liveLink && (
          <a href={project.liveLink} target="_blank" rel="noreferrer" className="card-link">
            Live Demo
          </a>
        )}
      </div>

      {/* 🔥 NEW BUTTONS */}
      <div style={{ marginTop: "10px" }}>
        <button
          className="card-link"
          onClick={() => navigate(`/edit-project/${project._id}`)}
        >
          ✏️ Edit
        </button>
      </div>

      {showDelete && (
        <button className="delete-btn" onClick={() => onDelete(project._id)}>
          Delete Project
        </button>
      )}
    </div>
  );
}

export default ProjectCard;
